INSERT INTO public.image_attributes (id, image_id, is_approved, alt_text_en, alt_text_it, scene_description)
VALUES
  ('7b456a49-203e-4bc5-b576-52973ecdfdb0', '91e0a25c-b81f-4e9b-88b9-38557827348e', true, 'Two Classy Cocktails Margarita bottles and two glasses of Margarita with lime slices, next to a brown box with "C like Cocktails" branding, all on a reflective dark surface with a gradient green background.', 'Due bottiglie di Classy Cocktails Margarita e due bicchieri di Margarita con fette di lime, accanto a una scatola marrone con il marchio "C like Cocktails", il tutto su una superficie scura riflettente con uno sfondo verde sfumato.', 'Two dark blue Classy Cocktails Margarita bottles stand on a reflective surface alongside two short glasses filled with a light-colored cocktail and garnished with lime slices. A brown branded box stands to the right. The background is a vibrant gradient of green and blue, creating a dynamic and modern studio setting.'),
  ('6692f861-4ebf-4214-a807-22f3ad96cdf4', '59862b8e-a17c-4fb1-bbed-dabbce313573', true, 'Two bottles of Classy Cocktails Espresso Martini and two glasses of the cocktail with ice and coffee beans next to a brown box with "C like Cocktails" branding.', 'Due bottiglie di Classy Cocktails Espresso Martini e due bicchieri del cocktail con ghiaccio e chicchi di caffè accanto a una scatola marrone con il marchio "C like Cocktails".', 'This studio shot features two black bottles of Classy Cocktails Espresso Martini alongside two glasses filled with the cocktail, ice, and coffee beans, all arranged on a reflective dark surface. A brown branded box stands to the right, adding a lifestyle element. The background is a soft, gradient beige.'),
  ('30261aa5-6e1e-4a70-aacd-d414b4ddd916', '9b21a837-6ed6-46bf-895c-91cf76027111', true, 'Two bottles of Classy Cocktails Daiquiri and two glasses with ice and a lime wedge, next to a branded cardboard box, on a reflective surface.', 'Due bottiglie di Classy Cocktails Daiquiri e due bicchieri con ghiaccio e una fetta di lime, accanto a una scatola di cartone brandizzata, su una superficie riflettente.', 'Two black bottles of Classy Cocktails Daiquiri stand on a reflective surface next to two short glasses filled with a yellow drink, ice, and a lime wedge. A brown cardboard box with "C like Chill, C like Cool, C like Cheers, C like Classy, C like Cocktails." printed on it is positioned to the right. The background is a vibrant gradient of green.'),
  ('09f5ff06-4eaf-4eaa-82f5-3ec2a157a789', 'b866140a-9f9b-431c-ae95-49879f0ce31f', true, 'Two Classy Cocktails Cosmopolitan bottles and two garnished cocktails in rocks glasses, positioned on a reflective surface in front of a red background, next to a brown box with branding.', 'Due bottiglie di Classy Cocktails Cosmopolitan e due cocktail guarniti in bicchieri rocks, posizionati su una superficie riflettente davanti a uno sfondo rosso, accanto a una scatola marrone con il marchio.', 'Two Classy Cocktails Cosmopolitan bottles stand on a reflective black surface, accompanied by two rocks glasses filled with cocktails and garnished with orange slices. A brown branded box stands upright on the right, all set against a vibrant red background. The scene suggests a sophisticated and inviting product presentation.'),
  ('5b44f84d-951c-486c-8416-219901cae26e', '01042c8a-92c7-45a4-a809-38797b36843e', true, 'Classy Cocktails Spicy Paloma bottle and cocktail. The cocktail is in a tall, frosted glass, filled with a light orange drink and ice. A red chili pepper garnish sits beside the bottle and glass, against a vibrant red background.', 'Bottiglia e cocktail Classy Cocktails Spicy Paloma. Il cocktail è in un bicchiere alto e satinato, riempito con una bevanda di colore arancione chiaro e ghiaccio. Un peperoncino rosso è adagiato accanto alla bottiglia e al bicchiere, su uno sfondo rosso vivace.', 'A vibrant and minimalist studio shot featuring a Classy Cocktails Spicy Paloma. The black bottle stands next to a tall, frosted glass containing the ready-to-drink cocktail with ice. A single red chili pepper provides a pop of contrasting color on the dark, reflective surface.'),
  ('b06f30e2-c912-4916-9ac0-511bf7a08874', '9ae93eac-0391-4649-a54e-3ecfe3080e04', true, 'A Classy Cocktails Cosmopolitan cocktail is poured from a stylish, dark bottle into a glass with a citrus garnish, with another garnished glass next to it, all set against a vibrant red background.', 'Un cocktail Cosmopolitan Classy Cocktails viene versato da un''elegante bottiglia scura in un bicchiere con una guarnizione di agrumi, con un altro bicchiere guarnito accanto, il tutto su uno sfondo rosso vibrante.', 'A hand pours a red cocktail from a Classy Cocktails bottle into a glass, garnished with an orange slice. Another glass with a red cocktail and orange slice sits nearby. The scene is set on a reflective surface against a bright red background.'),
  ('789847cb-627d-46bb-ae55-7122a603f963', '3dc65c0a-4ae2-48c5-9aa0-4d9da772ce1d', true, 'Two black bottles of Classy Cocktails Spicy Paloma, a glass with the cocktail and a red chili pepper on a glossy surface against a red background, with a Classy Cocktails brand box.', 'Due bottiglie nere di Classy Cocktails Spicy Paloma, un bicchiere con il cocktail e un peperoncino rosso su una superficie lucida su uno sfondo rosso, con una scatola del marchio Classy Cocktails.', 'Two Classy Cocktails Spicy Paloma bottles stand on a reflective surface alongside a tall glass filled with the cocktail and ice. A vibrant red chili pepper rests next to the glass. In the background, a brown Classy Cocktails box with brand messaging is visible, all set against a gradient red backdrop.'),
  ('6558e2ce-7df3-4ce1-99f4-69472023d532', '232458f5-240e-4a01-8361-387cf7b2cd1c', true, 'Two bottles of Classy Cocktails No Regrets Negroni, two glasses with orange slices, and a Classy Cocktails branded box with text "C like Chill, C like Cool, C like Cheers, C like Classy, C like Cocktails" set against a vibrant red background.', 'Due bottiglie di Classy Cocktails No Regrets Negroni, due bicchieri con fette d''arancia e una scatola a marchio Classy Cocktails con il testo "C like Chill, C like Cool, C like Cheers, C like Classy, C like Cocktails" su uno sfondo rosso vibrante.', 'Two bottles of Classy Cocktails No Regrets Negroni stand on the left, next to two glasses filled with the drink and garnished with orange slices. A brown Classy Cocktails branded box with a play on words using the letter C is positioned on the right. The background is a bright red, and the surface reflects the items, creating a modern and striking product shot.'),
  ('3078a817-2761-4a5d-8d1b-a62639911dc2', 'e1980b57-2217-4144-ad15-836a7adc759e', true, '', '', ''),
  ('157f8c87-4046-4cfe-8af0-94bfaba4232a', '6ff7327d-dc70-4b10-b767-8905b0f71bcd', true, '', '', ''),
  ('05066932-a8f2-46b7-94ef-a1ef0041c1bb', '7de73ce4-f19d-473a-be17-bc4e7decaa6f', true, 'Classy Cocktails No Regrets Negroni bottle and two filled glasses with orange slices on a reflective red surface.', 'Bottiglia di Classy Cocktails No Regrets Negroni e due bicchieri pieni con fette d''arancia su una superficie rossa riflettente.', 'A studio shot featuring a Classy Cocktails No Regrets Negroni bottle positioned centrally with two glasses of the drink, garnished with orange slices, on either side. The reflective red surface beneath the items creates a mirrored effect, emphasizing the product and its presentation.'),
  ('6eea1912-06e7-4033-a180-8d3789bf9a3c', '1f57bdce-fdc8-4de7-96af-d3285135e75b', true, 'A Classy Cocktails Daiquiri bottle pouring liquid into a glass, with a second filled cocktail glass beside it on a reflective dark surface against a vibrant green background.', 'Una bottiglia di Classy Cocktails Daiquiri versa del liquido in un bicchiere, con un secondo bicchiere da cocktail già pieno accanto su una superficie scura riflettente su uno sfondo verde vibrante.', 'A hand pours a Classy Cocktails Daiquiri from its bottle into a glass, next to another identical cocktail glass already filled. The clear glasses sit on a dark, reflective surface, contrasting with the bright, gradient green background.'),
  ('6e8e49dd-a085-4e1c-9c94-56f7e4719aa2', 'c15d1cad-7285-47a8-924e-2eec40aa1f0c', true, 'A person', 'Una persona sta versando un cocktail Paper Plane da una bottiglia Classy Cocktails in un bicchiere. Accanto al bicchiere con una fetta di limone, su uno sfondo rosso sfumato, suggerisce un momento di preparazione o servizio sofisticato.', 'A hand is pouring a Paper Plane cocktail from a Classy Cocktails bottle into a glass. Another glass with a lemon slice is next to it, against a gradient red background. The scene suggests a sophisticated drink preparation or serving moment.'),
  ('1d475a04-6cb1-4ca6-8888-df89eab8c06f', '65bf6e0d-699d-4345-82f7-dd316e6dd992', true, 'A hand pours a Classy Cocktails Margarita from a sleek, dark bottle into a glass with ice and a lime wedge, next to another similar glass, all against a vibrant teal and dark background.', 'Una mano versa un Margarita Classy Cocktails da una bottiglia scura ed elegante in un bicchiere con ghiaccio e una fetta di lime, accanto a un altro bicchiere simile, il tutto su uno sfondo vivace color verde acqua e scuro.', 'A hand is caught in the act of pouring a ready-to-drink Margarita from a stylish, dark bottle into a clear, short glass filled with ice and garnished with a lime wedge. A second identical glass, already prepared, sits nearby. The entire arrangement is set against a split background of bright teal above and a reflective dark surface below, creating a striking visual contrast.'),
  ('240e194f-d678-4c8c-b910-b8c69b46672c', '3f6c685c-fa7a-47f3-bea0-b5a75cd1ff16', true, 'A Classy Cocktails Espresso Martini is poured from a sleek black bottle into a glass with ice. Another full glass sits to the side on a reflective dark surface against a light background.', 'Un Espresso Martini Classy Cocktails viene versato da una bottiglia nera ed elegante in un bicchiere con ghiaccio. Un altro bicchiere pieno è posto di lato su una superficie scura e riflettente contro uno sfondo chiaro.', 'A hand pours a Classy Cocktail Espresso Martini from a black bottle into a clear glass containing a large ice cube, creating a rich brown drink. A second, identical glass, already filled with the cocktail and an ice cube, sits beside it, reflecting on the dark, shiny surface. The backdrop is a simple, light gradient.'),
  ('b70de05b-31c5-4d47-ad32-13f6a0fc43af', '9cbf3e2e-e607-4a29-98b5-d8612a61d20f', true, 'Classy Cocktails Cosmopolitan bottle and two glasses with cocktail and orange slices on a reflective surface with a red background.', 'Bottiglia di Classy Cocktails Cosmopolitan e due bicchieri con cocktail e fette d''arancia su una superficie riflettente con sfondo rosso.', 'A Classy Cocktails Cosmopolitan bottle stands between two rocks glasses filled with a red cocktail and ice. One glass is garnished with an orange slice. The items are arranged on a highly reflective black surface, set against a vibrant red background, emphasizing the product with a warm glow.'),
  ('03829656-f3d3-406d-baf8-aab2e5b3fee2', 'fdaf3693-d8b4-497a-b60c-93ce3ec8783f', true, 'A person pouring a Classy Cocktails Spritz into a glass with an orange peel on a dark surface, against an orange background.', 'Una persona versa uno Spritz Classy Cocktails in un bicchiere con una scorza d''arancia su una superficie scura, su uno sfondo arancione.', 'A hand is pouring golden liquid from a Classy Cocktails Spritz bottle into a clear, tall glass with a large ice cube. An orange peel garnish rests on the glossy dark surface next to the glass. The background is a vibrant, gradient orange, creating a striking contrast with the darker foreground.'),
  ('6840a8d1-3ba9-4111-8175-4bc403037ac2', '5116ef73-c05d-4922-a954-a27659069f23', true, 'A person in a black suit meticulously pouring a spicy paloma cocktail from a sleek black bottle into a tall glass with ice and a red chili pepper on a reflective red surface.', 'Una persona in completo nero versa meticolosamente un cocktail Spicy Paloma da un''elegante bottiglia nera in un bicchiere alto con ghiaccio e un peperoncino rosso su una superficie riflettente rossa.', 'A person is captured in the act of pouring a spicy paloma cocktail. The setting emphasizes the vibrant red of the background and surface, creating a dynamic and stylish presentation. A single red chili pepper rests on the surface, hinting at the drink''s spicy flavor profile.'),
  ('1b68e241-0482-44f4-b67b-908e3444be7b', 'ba2bba9d-faa8-47c7-8906-247ddce07f50', true, 'A person', 'Una persona versa un liquido scuro da una bottiglia di Classy Cocktails "No Regrets Moment" in un bicchiere old fashioned con ghiaccio. Due bicchieri sono su una superficie riflettente su uno sfondo verde brillante, uno dei quali guarnito con una fetta di agrume essiccato.', 'A hand is pouring a dark liquid from a Classy Cocktails "No Regrets Moment" bottle into a rocks glass with ice. Two rocks glasses are on a reflective surface against a vibrant green background, one of them garnished with a dried citrus slice.'),
  ('93c11242-2fd6-4ef5-8889-52ad687b600f', '0fbca478-cb4b-4e0a-88ff-e7bf4622d324', true, 'A person pours a vibrant red Negroni cocktail from a Classy Cocktails bottle into a glass, with another glass already prepared and garnished with citrus peel, all set against a striking red backdrop.', 'Una persona versa un vibrante cocktail Negroni rosso dalla bottiglia Classy Cocktails in un bicchiere, con un altro bicchiere già preparato e guarnito con scorza di agrumi, il tutto su uno sfondo rosso sorprendente.', 'A hand is depicted pouring a vibrant red Classy Cocktails Negroni into a clear glass, with the cocktail splashing artfully. Beside it, another glass of Negroni, garnished with a yellow citrus peel, stands ready. The setting features a gradient red background that transitions into a darker, reflective surface.'),
  ('4f94a63c-72d9-4cf3-af26-816fa13d1139', '2620afe5-dfe1-49f8-a25f-1f1dab237967', true, 'Classy Cocktails Negroni bottle and two garnished cocktails on a reflective surface with a red background, ideal for product showcases.', 'Bottiglia di Classy Cocktails Negroni e due cocktail guarniti su una superficie riflettente con sfondo rosso, ideale per l''esposizione del prodotto.', 'A Classy Cocktails Negroni bottle is centered between two rocks glasses, both filled with Negroni cocktails and garnished with an orange peel. The items are arranged on a dark, reflective surface against a vibrant red backdrop, creating a striking contrast that highlights the product.'),
  ('d271d750-172a-40db-8692-435dbc696b03', '44ca39c1-cfe5-4288-b6be-6b9d57f278ab', true, 'Classy Cocktails Espresso Martini bottle and two glasses with cocktail and coffee beans on a reflective surface.', 'Bottiglia di Espresso Martini Classy Cocktails e due bicchieri con cocktail e chicchi di caffè su una superficie riflettente.', 'A Classy Cocktails Espresso Martini bottle stands centrally on a highly reflective dark surface, flanked by two glasses containing the cocktail with ice and coffee beans. The background is a subtly lit, light peach colour, creating a stark contrast with the darker darker foreground elements.'),
  ('1211da16-0005-472b-a835-6fe835d470ae', '105f00f9-7542-4fc0-92c2-6bc410fe0d9a', true, '', '', ''),
  ('ebb86303-24b3-49d7-b1dd-b975eab97c93', 'bcde73a3-6726-4285-b736-0c2cce8da32b', true, 'Classy Cocktails Margarita can next to two glasses of margarita with lime slices and ice on a reflective dark surface with a gradient green background.', 'Lattina Classy Cocktails Margarita accanto a due bicchieri di margarita con fette di lime e ghiaccio su una superficie scura riflettente con uno sfondo verde sfumato.', 'A Classy Cocktails Margarita bottle stands centered between two rocks glasses filled with a clear liquid, ice, and lime wedges. The setup is arranged on a highly reflective dark surface, creating a mirror effect of the bottle and glasses. A vibrant gradient background transitions from bright turquoise to a darker green, adding a dynamic contrast to the dark foreground.'),
  ('c42560a1-79fe-474a-b227-75684f406849', 'a7e76f5f-fb1e-45af-802b-af8cb39e1dd8', true, '', '', ''),
  ('858228f3-a506-4966-9229-b5b967894dd6', '68921ab5-f358-4d76-9d26-d4fd6825c9dd', true, 'A bottle of Classy Cocktails No Regrets Moment and two glasses with non-alcoholic cocktails, garnished with ginger slices, against a vibrant green background.', 'Una bottiglia di Classy Cocktails No Regrets Moment e due bicchieri con cocktail analcolici, guarniti con fette di zenzero, su uno sfondo verde vibrante.', 'A studio shot featuring a bottle of Classy Cocktails No Regrets Moment, flanked by two glasses of a dark red non-alcoholic cocktail. The drinks are garnished with ginger slices, and the setup is against a vivid green background with a reflective surface creating clear reflections of the bottle and glasses. This image highlights the product and its serving suggestion.'),
  ('b084e910-01ee-4b74-a924-d176ba196cfb', '4cb0e1e0-eadf-4642-9b92-e39106554ffa', true, 'Classy Cocktails Daiquiri bottle next to two glasses of Daiquiri with ice and a lime wedge, against a vibrant green and dark blue background.', 'Bottiglia di Daiquiri Classy Cocktails accanto a due bicchieri di Daiquiri con ghiaccio e uno spicchio di lime, su uno sfondo verde accesso e blu scuro.', 'A studio shot featuring a Classy Cocktails Daiquiri bottle, flanked by two rocks glasses filled with the cocktail and ice. One glass is garnished with a lime wedge. The reflective surface and gradient background create a sleek and modern aesthetic.'),
  ('8260b234-cf41-4bb4-94f1-07209b3fe796', '2c5855a1-0301-46a9-98cc-b685b0921f95', true, 'A low-light studio shot of a hand pouring a dark liquid from a Classy Cocktails "No Regrets Negroni" bottle into a rocks glass, with another garnished glass and an empty bottle resting on a reflective red surface.', 'Immagine in studio, in condizioni di scarsa illuminazione. Una mano versa un liquido scuro da una bottiglia Classy Cocktails "No Regrets Negroni" in un bicchiere old fashioned, un altro bicchiere guarnito e una bottiglia vuota giacciono su una superficie rossa riflettente.', 'In a darkly lit studio, a hand is captured mid-air, pouring a rich, dark red liquid from a Classy Cocktails "No Regrets Negroni" bottle into a rocks glass. To the left, another rocks glass, already filled with the same beverage, is garnished with a vibrant orange slice. An empty bottle lies on the reflective surface, further suggesting a serving moment.'),
  ('fc6dc9e3-3884-4f6d-9165-de2122771a95', 'a1f4f8e9-e4a1-4fa3-aec8-71788d6d3311', true, 'Two Classy Cocktails Paper Plane bottles stand next to two glasses of the cocktail, garnished with a lemon peel, alongside a brown box with "C like Cocktails" messaging, all on a reflective surface against a vibrant red background.', 'Due bottiglie di Classy Cocktails Paper Plane affiancate a due bicchieri del cocktail guarniti con scorza di limone, accanto a una scatola marrone con il messaggio "C like Cocktails", il tutto su una superficie riflettente con sfondo rosso vibrante.', 'Two Classy Cocktails Paper Plane bottles are presented with two glasses of the prepared cocktail, each garnished with a lemon peel. A branded brown box is also featured, displaying playful "C like" phrases and the brand name. The setup is on a highly reflective black surface, contrasting with a bold red background, creating a sleek and modern product shot.'),
  ('3c17bfbc-50f2-4876-bbb7-0e10a5172ced', 'b5d18eaf-fc91-4eda-a1b8-cd9b80f92ccc', true, 'Two Classy Cocktails Negroni bottles and two garnished Negroni cocktails in glasses, with a "C like Cocktails" box, all set against a vibrant red backdrop.', 'Due bottiglie di Negroni Classy Cocktails e due cocktail Negroni guarniti in bicchieri, con una scatola "C like Cocktails", il tutto su uno sfondo rosso vibrante.', 'Two dark Classy Cocktails Negroni bottles stand alongside two rocks glasses filled with Negroni cocktails, each garnished with an orange peel. A brown cardboard box with black text that reads "C like Chill, C like Cool, C like Cheers, C like Classy, C like Cocktails." is positioned on the right. The items are arranged on a reflective dark surface against a bright red background.'),
  ('915fd7cd-0c0f-4f4a-8a89-81c31cf947d0', '748a287a-acd4-4d89-83e6-09dabed8a9bd', true, '', '', ''),
